--
-- Table structure for table `employee_documents`
--

DROP TABLE IF EXISTS `employee_documents`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `employee_documents` (
  `id` int NOT NULL AUTO_INCREMENT,
  `employeeId` int NOT NULL,
  `companyId` int NOT NULL,
  `departmentId` int DEFAULT NULL,
  `aadhaarNumber` varchar(255) DEFAULT NULL,
  `aadhaarDocument` varchar(255) DEFAULT NULL COMMENT 'Filename of Aadhaar document',
  `panNumber` varchar(255) DEFAULT NULL,
  `panDocument` varchar(255) DEFAULT NULL COMMENT 'Filename of PAN document',
  `passportNumber` varchar(255) DEFAULT NULL,
  `passportDocument` varchar(255) DEFAULT NULL COMMENT 'Filename of Passport document',
  `voterIdNumber` varchar(255) DEFAULT NULL,
  `voterIdDocument` varchar(255) DEFAULT NULL COMMENT 'Filename of Voter ID document',
  `drivingLicenseNumber` varchar(255) DEFAULT NULL,
  `drivingLicenseDocument` varchar(255) DEFAULT NULL COMMENT 'Filename of Driving License document',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `employeeId` (`employeeId`),
  KEY `companyId` (`companyId`),
  KEY `departmentId` (`departmentId`),
  CONSTRAINT `employee_documents_ibfk_1` FOREIGN KEY (`employeeId`) REFERENCES `employees` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `employee_documents_ibfk_2` FOREIGN KEY (`companyId`) REFERENCES `companies` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `employee_documents_ibfk_3` FOREIGN KEY (`departmentId`) REFERENCES `departments` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `employee_documents`
--

LOCK TABLES `employee_documents` WRITE;
/*!40000 ALTER TABLE `employee_documents` DISABLE KEYS */;
/*!40000 ALTER TABLE `employee_documents` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `employee_loans`
--

DROP TABLE IF EXISTS `employee_loans`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `employee_loans` (
  `id` int NOT NULL AUTO_INCREMENT,
  `employeeId` int NOT NULL,
