  `validFrom` datetime DEFAULT NULL COMMENT 'Date from which this formula is valid',
  `validTo` datetime DEFAULT NULL COMMENT 'Date until which this formula is valid',
  `priority` int NOT NULL DEFAULT '0' COMMENT 'Execution priority (lower number = higher priority)',
  `companyId` int NOT NULL,
  `createdBy` int DEFAULT NULL COMMENT 'User ID who created this formula',
  `updatedBy` int DEFAULT NULL COMMENT 'User ID who last updated this formula',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`),
